+fn selected_strategy_ids() -> Vec<String> {
+    let Ok(raw) = env::var(STRATEGY_ENV_FILTER) else {
+        return DEFAULT_STRATEGY_IDS
+            .iter()
+            .map(|id| (*id).to_owned())
